import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"更新 Fabric","description":"有關如何更新 Fabric 的逐步指南。","frontmatter":{"title":"更新 Fabric","description":"有關如何更新 Fabric 的逐步指南。","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.8/players/updating-fabric.md","filePath":"versions/1.21.8/translated/zh_tw/players/updating-fabric.md","lastUpdated":1760721669000}`);var s={name:`zh_tw/1.21.8/players/updating-fabric.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">更新 Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “更新 Fabric”">​</a></h1><p>這個指南將引導你在 Minecraft 啟動器上更新 Fabric。</p><p>對於第三方啟動器，您應該查閱其說明文件。</p><p>更新 Fabric 的過程與安裝 Fabric 非常相似，因此本指南的某些部分將與<a href="./installing-fabric">安裝 Fabric</a> 指南相同。</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">為什麼我應該更新 Fabric 載入器？ <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “為什麼我應該更新 Fabric 載入器？”">​</a></h2><p>較新的模組可能需要較新版本的 Fabric 載入器才能運作，因此保持最新狀態以確保您可以使用最新的模組非常重要。</p><p>對於第三方啟動器，你應該參考它們的文件。</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. 下載 Fabric 安裝程式 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. 下載 Fabric 安裝程式”">​</a></h2><p>你可以從 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 官網</a>下載 Fabric 安裝程式。</p><p>如果你使用 Windows 作業系統，請下載 <code>.exe</code> 版本（<code>Download For Windows</code>），因為它不需要在你的系統上安裝 Java。 它改為使用官方啟動器附帶的 Java。</p><p>對於 macOS 和 Linux 使用者，你應該下載 <code>.jar</code> 版本。 有時，在進行這個步驟之前，你需要安裝 Java。</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. 執行 Fabric 安裝程式 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. 執行 Fabric 安裝程式”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>在安裝前，請先關閉 Minecraft 和 Minecraft 啟動器。</p></div><details class="details custom-block"><summary>對於 macOS 使用者的資訊</summary><p>在 macOS 上，你可能需要在下載目錄中對 <code>.jar</code> 檔案按下右鍵，然後選擇 <code>打開</code> 才能執行它。</p><p>Fabric 安裝程式上的 macOS 右鍵選單</p><p>當詢問「你確定要打開它嗎？」時，請再次按下「打開」。</p></details><p>開啟安裝程式後，你應該會看到以下視窗：</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric 安裝程式，「安裝」按鈕已醒目顯示" loading="lazy"></p><p>要安裝 Fabric，只需從下拉式選單中選擇你的遊戲版本，然後點選 <code>安裝</code>。</p><p>要更新 Fabric，只需確保遊戲版本和載入器版本正確，然後按一下 <code>安裝</code>。</p><p>:::important 執行安裝程式時，請務必取消勾選「建立設定檔」，否則它將建立新的設定檔，在這種情況下我們不需要。 :::</p><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. 在 Minecraft 啟動器中開啟設定檔 <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. 在 Minecraft 啟動器中開啟設定檔”">​</a></h2><p>安裝程式完成後，您可以開啟 Minecraft 啟動器並前往 <code>安裝檔</code> 頁籤。 您應該前往您的 Fabric 設定檔並開啟編輯畫面。</p><p>將版本替換為您剛才安裝的新版 Fabric 載入器，然後按下 <code>儲存</code>。</p><p><img src="/assets/players/updating-fabric.png" alt="在 Minecraft 啟動器中更新 Fabric 載入器版本" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. 你完成了！ <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. 你完成了！”">​</a></h2><p>完成這些步驟後，您可以返回 <code>開始遊戲</code> 頁籤，從左下方的下拉式選單中選擇 Fabric 設定檔，然後按下「開始遊戲」！</p><p>如果您在遵循本指南時遇到任何問題，您可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 頻道中尋求幫助。</p>`,26)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};